30	function surchargeRate(item: Item): number {
31	  const curseRate = item.cursed ? CURSE_SURCHARGE_RATE : 0;
32	  const highEnchantmentRate =
33	    (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD
34	      ? HIGH_ENCHANTMENT_SURCHARGE_RATE
35	      : 0;
36	  return curseRate + highEnchantmentRate;
37	}
