const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  rune: 25,
  moonstone: 25,
};

const COMPONENT_TYPES = new Set(["rune", "moonstone"]);

function surchargeRate(item: Item): number {
  const curseRate = item.cursed ? CURSE_SURCHARGE_RATE : 0;
  const highEnchantmentRate =
    (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD
      ? HIGH_ENCHANTMENT_SURCHARGE_RATE
      : 0;
  return curseRate + highEnchantmentRate;
}

function nonComponentItemPremium(item: Item): number {
  const base = BASE_PREMIUMS[item.type];
  return base * (1 + surchargeRate(item));
}

function componentBasePremium(count: number, unitPrice: number): number {
  return count === COMPONENT_BLOCK_SIZE
    ? COMPONENT_BLOCK_PRICE
    : count * unitPrice;
}

function itemsBasePremium(items: Item[]): number {
  const componentCounts: Record<string, number> = {};
  let nonComponentBase = 0;
  for (const item of items) {
    if (COMPONENT_TYPES.has(item.type)) {
      componentCounts[item.type] = (componentCounts[item.type] ?? 0) + 1;
    } else {
      nonComponentBase += nonComponentItemPremium(item);
    }
  }
  const componentBase = Object.entries(componentCounts).reduce(
    (total, [type, count]) =>
      total + componentBasePremium(count, BASE_PREMIUMS[type]),
    0
  );
  return nonComponentBase + componentBase;
}

const LOYALTY_THRESHOLD_YEARS = 2;
const LOYALTY_DISCOUNT_RATE = 0.2;

export function quote(customer: Customer, items: Item[]): number {
  const itemsBase = itemsBasePremium(items);
  const insuranceSurcharge = itemsBase * INSURANCE_SURCHARGE_RATE;
  const loyaltyDiscount =
    customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS
      ? itemsBase * LOYALTY_DISCOUNT_RATE
      : 0;
  return Math.ceil(
    itemsBase + insuranceSurcharge - loyaltyDiscount + PROCESSING_FEE
  );
}

