      { type: "rune" },
      { type: "rune" },
      { type: "rune" }
    ])).toBe(115);
  });
  it("quote with 7 runes returns 175 base premium (one block of 3 + 4 single = 60 + 100)", () => {
    expect(quote({ yearsWithMHPCO: 0 }, [
