      { type: "rune" },
      { type: "rune" },
      { type: "rune" },
      { type: "rune" },
      { type: "rune" },
      { type: "rune" }
    ])).toBe(198);
  });
  it("quote with 2 runes + 1 moonstone returns 75 base premium (no block: different types)", () => {
    expect(quote({ yearsWithMHPCO: 0 }, [
      { type: "rune" },
      { type: "rune" },
      { type: "moonstone" }
    ])).toBe(88);
