import { quote, createPolicy, claim } from "./claim-office.js";

async function readStdin(): Promise<string> {
  const chunks: Buffer[] = [];
  for await (const chunk of process.stdin) {
    chunks.push(chunk as Buffer);
  }
  return Buffer.concat(chunks).toString("utf-8");
}

async function main(): Promise<void> {
  const input = await readStdin();
  const scenario = JSON.parse(input);
  const customer = scenario.customer;
  const steps = scenario.steps;
  const results: unknown[] = [];
  const policiesByStep: Record<number, ReturnType<typeof createPolicy>> = {};
  let priorQuoteCount = 0;
  for (let i = 0; i < steps.length; i++) {
    const step = steps[i];
    if (step.op === "quote") {
      const customerForQuote = {
        ...customer,
        previousContracts: (customer.previousContracts ?? 0) + priorQuoteCount,
      };
      const premium = quote(customerForQuote, step.items);
      results.push({ premium });
      policiesByStep[i] = createPolicy(step.items);
      priorQuoteCount++;
    } else if (step.op === "claim") {
      const policy = policiesByStep[step.policy];
      const result = claim(policy, step.incident);
      results.push({ payout: result.payout, remainingCap: result.remainingCap });
    }
  }
  process.stdout.write(JSON.stringify({ results }));
}

main().catch((err) => {
  process.stderr.write(String(err?.message ?? err) + "\n");
  process.exit(1);
});
